DROP TABLE IF EXISTS `operator_review_queue_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `operator_review_queue_items` (
  `id` varchar(191) NOT NULL,
  `workflow_family` varchar(64) NOT NULL,
  `session_id` varchar(191) NOT NULL,
  `source_artifact_id` varchar(191) DEFAULT NULL,
  `source_artifact_path` text DEFAULT NULL,
  `queue_type` varchar(128) NOT NULL,
  `state` varchar(64) NOT NULL,
  `priority` varchar(64) NOT NULL DEFAULT 'unknown',
  `recommended_action_id` varchar(128) DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `detail_text` text DEFAULT NULL,
  `href` varchar(255) DEFAULT NULL,
  `active` tinyint(1) NOT NULL DEFAULT 1,
  `metadata_json` longtext DEFAULT NULL,
  `created_at` datetime(3) NOT NULL,
  `updated_at` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_operator_review_queue_session_id_active` (`session_id`,`active`),
  KEY `idx_operator_review_queue_workflow_family` (`workflow_family`),
  KEY `idx_operator_review_queue_state` (`state`),
  KEY `fk_operator_review_queue_source_artifact` (`source_artifact_id`),
  CONSTRAINT `fk_operator_review_queue_session` FOREIGN KEY (`session_id`) REFERENCES `operator_workflow_sessions` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_operator_review_queue_source_artifact` FOREIGN KEY (`source_artifact_id`) REFERENCES `operator_artifacts` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
