DROP TABLE IF EXISTS `operator_system_signals`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8mb4 */;
CREATE TABLE `operator_system_signals` (
  `id` varchar(191) NOT NULL,
  `workflow_family` varchar(64) DEFAULT NULL,
  `signal_type` varchar(128) NOT NULL,
  `severity` varchar(32) NOT NULL DEFAULT 'info',
  `state` varchar(64) NOT NULL DEFAULT 'open',
  `title` varchar(255) NOT NULL,
  `summary` text DEFAULT NULL,
  `href` varchar(255) DEFAULT NULL,
  `active` tinyint(1) NOT NULL DEFAULT 1,
  `session_id` varchar(191) DEFAULT NULL,
  `artifact_id` varchar(191) DEFAULT NULL,
  `job_run_id` varchar(191) DEFAULT NULL,
  `metadata_json` longtext DEFAULT NULL,
  `observed_at` datetime(3) NOT NULL,
  `resolved_at` datetime(3) DEFAULT NULL,
  `created_at` datetime(3) NOT NULL,
  `updated_at` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_operator_system_signals_active` (`active`),
  KEY `idx_operator_system_signals_workflow_family` (`workflow_family`),
  KEY `idx_operator_system_signals_severity` (`severity`),
  KEY `fk_operator_system_signals_session` (`session_id`),
  KEY `fk_operator_system_signals_artifact` (`artifact_id`),
  KEY `fk_operator_system_signals_job` (`job_run_id`),
  CONSTRAINT `fk_operator_system_signals_artifact` FOREIGN KEY (`artifact_id`) REFERENCES `operator_artifacts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_operator_system_signals_job` FOREIGN KEY (`job_run_id`) REFERENCES `operator_job_runs` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_operator_system_signals_session` FOREIGN KEY (`session_id`) REFERENCES `operator_workflow_sessions` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

